class Solution {
    public long maxGCDScore(int[] nums, int k) {
        int n = nums.length;
        long[] dp = new long[n + 1];
        long[] gcd = new long[n + 1];
        gcd[0] = 1;
        for (int i = 1; i <= n; i++) {
            gcd[i] = nums[i - 1];
            for (int j = i - 1; j >= 1; j--) {
                gcd[i] = gcd(gcd[i], nums[j - 1]);
            }
        }
        for (int i = 1; i <= n; i++) {
            dp[i] = dp[i - 1];
            for (int j = 1; j <= Math.min(i, k); j++) {
                dp[i] = Math.max(dp[i], (i - j + 1) * gcd[i]);
            }
        }
        return dp[n];
    }
    private long gcd(long a, long b) {
        return b == 0 ? a : gcd(b, a % b);
    }
}
